def _mode_family(mode: str) -> str:
    normalized = str(mode or "").upper()
    if normalized in {"AGGRESSIVE", "MODERATE_BULL", "MILD_BULL"}:
        return "RISK_ON"
    if not normalized or normalized in {"BALANCED", "CAUTIOUS", "NEUTRAL"}:
        return "BALANCED"
    return "RISK_OFF"
def _normalize_strategy_name(raw: str) -> str:
    value = str(raw or "").strip()
    if not value:
        return ""
    normalized = _STRATEGY_NAME_MAP.get(value)
    if normalized is not None:
        return normalized
    normalized = _STRATEGY_NAME_MAP.get(value.lower())
    if normalized is not None:
        return normalized
    return ""


_ANALYST_ROLES = ("bull", "bear", "neutral")


def _is_triage_shim_vote(vote: dict) -> bool:
    return isinstance(vote, dict) and bool(vote.get("triage_shim"))


def _analyst_role_votes(judgments: dict) -> list[tuple[str, dict]]:
    if not isinstance(judgments, dict):
        return []
    return [
        (role, vote)
        for role in _ANALYST_ROLES
        if isinstance((vote := judgments.get(role)), dict)
    ]


def _average_analyst_confidence(judgments: dict, default: float = 0.5) -> float:
    role_votes = _analyst_role_votes(judgments)
    if not role_votes:
        return default

    real_conf = [
        float(vote.get("confidence", default) or 0.0)
        for _, vote in role_votes
        if not _is_triage_shim_vote(vote)
    ]
    if real_conf:
        return sum(real_conf) / len(real_conf)

    shim_conf = [
        float(vote.get("confidence", default) or 0.0)
        for _, vote in role_votes
        if _is_triage_shim_vote(vote)
    ]
    if shim_conf:
        return sum(shim_conf) / len(shim_conf)
    return default


def _analyst_strategy_vote(judgments: dict) -> str:
    """
    3명 분석가 suggested_strategy 다수결 → 코드 전략명.
    2표 이상 일치 없으면 빈 문자열 반환.
    """
    from collections import Counter
    votes = [
        _normalize_strategy_name(vote.get("suggested_strategy", ""))
        for _, vote in _analyst_role_votes(judgments)
        if not _is_triage_shim_vote(vote)
    ]
    valid = [v for v in votes if v]
    if not valid:
        return ""
    top, top_count = Counter(valid).most_common(1)[0]
    return top if top_count >= 2 else ""
def _env_bool(name: str, default: bool = False) -> bool:
    raw = os.getenv(name)
    if raw is None:
        return default
    return str(raw).strip().lower() in ("1", "true", "yes", "y", "on")
def _sub_screener_trigger_enabled(market: str) -> bool:
    market_key = "US" if str(market or "").upper() == "US" else "KR"
    scoped_name = f"SUB_SCREENER_{market_key}_TRIGGER_ENABLED"
    if os.getenv(scoped_name) is not None:
        return _env_bool(scoped_name, False)
    return _env_bool("SUB_SCREENER_TRIGGER_ENABLED", True)
def _env_float_value(name: str, default: float) -> float:
    raw = os.getenv(name)
    if raw in (None, ""):
        return float(default)
    try:
        return float(str(raw).strip())
    except Exception:
        return float(default)
def _market_env_float(market: str, suffix: str, default: float) -> float:
    market_key = "US" if str(market or "").upper() == "US" else "KR"
    scoped_name = f"{market_key}_{suffix}"
    if os.getenv(scoped_name) not in (None, ""):
        return _env_float_value(scoped_name, default)
    return _env_float_value(suffix, default)
def _market_dynamic_universe_top_n_env(market: str) -> int:
    market_key = str(market or "").upper()
    default = _DYNAMIC_UNIVERSE_TOP_N_DEFAULTS.get(market_key, 20)
    raw = os.getenv(f"{market_key}_DYNAMIC_UNIVERSE_TOP_N")
    if raw is None:
        raw = os.getenv("DYNAMIC_UNIVERSE_TOP_N", str(default))
    try:
        return int(raw)
    except Exception:
        return default
def _v2_fresh_brain_policy_enabled() -> bool:
    policy = str(os.getenv("V2_BRAIN_POLICY", "") or "").strip().lower()
    if policy in {"fresh", "fresh_v2", "fresh_v2_reference_v1"}:
        return True
    return _env_bool("V2_FRESH_BRAIN_START", False)
def _enabled_markets_from_env() -> set[str]:
    raw = str(os.getenv("ENABLED_MARKETS", "KR,US") or "KR,US")
    markets = {item.strip().upper() for item in raw.split(",") if item.strip()}
    return markets & {"KR", "US"} or {"KR", "US"}
class TradingBot(MarketUtilsMixin, StateMixin):
    def __init__(self, is_paper: bool = True):
        self.is_paper = is_paper
        self.enabled_markets = _enabled_markets_from_env()
        self.startup_disabled_markets: dict[str, str] = {}
        self.tokens: dict[str, str] = {}
        self.token = ""
        self.v2 = _V2LifecycleRuntime(self, is_paper=is_paper) if _V2_LIFECYCLE_AVAILABLE else None
        self.usd_krw_rate = float(os.getenv("USD_KRW_RATE", "1350"))
        if self.v2 is None:
            self.v2_lifecycle_enabled = False
            self.v2_registry = None
            self.v2_brain_snapshot_store = None
            self.v2_decision_ids: dict[str, dict[str, str]] = {"KR": {}, "US": {}}
            self.v2_brain_snapshot_ids: dict[str, str] = {"KR": "", "US": ""}
            self.v2_fixed_sizing_enabled = False
            self.v2_fixed_sizer = None
            self.v2_safety_gate = None
            self.v2_partial_fill_policy = None
            self.v2_order_unknown = None
            self.v2_order_rate_limiter = None
            self.v2_risk_profiles = {}
            self._v2_same_day_stop_tickers: dict[str, set[str]] = {"KR": set(), "US": set()}
        # ── 투자 금액 설정 — KIS 잔고 직접 조회 (모의/실거래 공통) ─────────
        mode_label = "paper" if is_paper else "live"
        _bal_retry_max = 3 if is_paper else 3
        _bal_retry_delay = 5
        bal_kr = None
        if not self._market_enabled("KR"):
            bal_kr = {"cash": 0, "total_eval": 0, "stocks": []}
            _log_normal("info", "KR disabled by ENABLED_MARKETS; skipping KR balance lookup")
        for _attempt in (range(1, _bal_retry_max + 1) if bal_kr is None else []):
            try:
                bal_kr = self._get_balance_with_token_refresh("KR")
                break
            except Exception as e:
                _log_risk("warning", f"KIS KR 잔고 조회 실패 ({_attempt}/{_bal_retry_max}): {e}")
                if _attempt < _bal_retry_max:
                    import time as _t; _t.sleep(_bal_retry_delay)
                else:
                    if is_paper:
                        _log_risk("warning", "KIS 서버 응답 없음 — PAPER_CASH 폴백으로 기동")
                        bal_kr = {"cash": int(os.getenv("PAPER_CASH", "10000000")), "total_eval": 0}
                    elif self._market_enabled("US"):
                        reason = f"KIS KR startup balance failed after {_bal_retry_max} attempts: {e}"
                        self.enabled_markets.discard("KR")
                        self.startup_disabled_markets["KR"] = reason
                        _log_risk("warning", f"{reason}; continuing with US only")
                        bal_kr = {"cash": 0, "total_eval": 0, "stocks": []}
                    else:
                        raise SystemExit(f"KIS 실거래 잔고 조회 {_bal_retry_max}회 실패 — 종료")
        init_cash = bal_kr["cash"] + bal_kr["total_eval"]
        if init_cash <= 0:
            if is_paper:
                init_cash = int(os.getenv("PAPER_CASH", "10000000"))
                _log_risk(
                    f"모의투자 잔고 0 → PAPER_CASH 폴백({init_cash:,}원) 사용. "
                    f"KIS 앱에서 모의투자 계좌 초기화 필요 (모의투자 메뉴 → 초기화)"
                )
            else:
                if self._market_enabled("US"):
                    reason = "KIS KR startup balance is zero"
                    self.enabled_markets.discard("KR")
                    self.startup_disabled_markets["KR"] = reason
                    _log_risk("warning", f"{reason}; continuing with US only")
                    init_cash = 0
                else:
                    raise SystemExit("잔고 0 — 실거래 계좌 확인 필요")
        env_cap = int(os.getenv("MAX_ORDER_KRW", "500000" if is_paper else "2000000"))
        order_pct = float(os.getenv("MAX_ORDER_PCT", "0.05"))
        max_order = min(env_cap, int(init_cash * order_pct))
        _log_normal(
            "info",
            f"{mode_label} | KIS KR 잔고 {init_cash:,}원 "
            f"(현금 {bal_kr['cash']:,} + 평가 {bal_kr['total_eval']:,}) "
            f"| max_order {max_order:,} KRW",
        )
        # US 잔고 조회 — 환전 현금 + 보유종목 표시, 공유 풀에 합산
        us_cash_init_krw = 0
        if self._market_enabled("US"):
            try:
                bal_us = self._get_balance_with_token_refresh("US")
                usd_krw = float(bal_us.get("kis_exchange_rate", 0) or get_usd_krw())
                self.usd_krw_rate = float(usd_krw)
                us_cash_usd    = float(bal_us.get("cash", 0) or 0)
                us_orderable_usd = float(bal_us.get("orderable_cash", us_cash_usd) or us_cash_usd)
                us_asset_cash_usd = float(bal_us.get("asset_cash", max(us_cash_usd, us_orderable_usd)) or 0)
                if us_asset_cash_usd <= 0:
                    us_asset_cash_usd = max(us_cash_usd, us_orderable_usd)
                us_cash_krw_   = int(float(bal_us.get("asset_cash_krw", 0) or 0) or us_asset_cash_usd * usd_krw)
                us_eval_usd    = float(bal_us.get("total_eval", 0) or 0)
                us_eval_krw    = int(us_eval_usd * usd_krw)
                _log_normal(
                    "info",
                    f"{mode_label} | KIS US balance ${us_asset_cash_usd:.2f} "
                    f"cash({us_cash_krw_:,} KRW) + ${us_eval_usd:.2f} eval({us_eval_krw:,} KRW)"
                    f" | positions {len(bal_us['stocks'])}",
                )
                if not self.is_paper:
                    us_cash_init_krw = us_cash_krw_
            except Exception as e:
                _log_risk("warning", f"KIS US 잔고 조회 실패 (무시): {e}")
                if not is_paper:
                    self.enabled_markets.discard("US")
                    self.startup_disabled_markets["US"] = f"KIS US startup balance failed: {e}"
        else:
            _log_normal("info", "US disabled by ENABLED_MARKETS; skipping US balance lookup")
        init_cash_total = init_cash + us_cash_init_krw
        if init_cash_total <= 0:
            if is_paper:
                init_cash_total = int(os.getenv("PAPER_CASH", "10000000"))
            else:
                raise SystemExit("No enabled market startup balance available")
        if max_order <= 0 and init_cash_total > 0:
            max_order = min(env_cap, int(init_cash_total * order_pct))
        self.risk = RiskManager(init_cash=init_cash_total, max_order_krw=max_order, market="KR")
        self._init_market_risk_shadow(
            init_cash_krw=init_cash,
            us_cash_init_krw=us_cash_init_krw,
            max_order_krw=max_order,
        )
        # KR/US 공유 풀 — 단일 현금 계좌, 시장 구분 없이 사용
        if us_cash_init_krw > 0:
            _log_normal("info", f"shared pool | total {init_cash_total:,.0f} KRW (KR {init_cash:,} + US {us_cash_init_krw:,})")
        else:
            _log_normal("info", f"shared pool | total {init_cash_total:,.0f} KRW (KR/US shared)")
        self.today_judgment = {}
        self.today_tickers: dict = {}   # {market: [ticker, ...]} — 매일 아침 Claude가 선택
        self.today_ticker_reasons: dict = {}
        self.trade_ready_tickers: dict[str, list[str]] = {"KR": [], "US": []}
        self.selection_meta: dict[str, dict] = {"KR": {}, "US": {}}
        self.selection_stages: dict[str, dict] = {"KR": {}, "US": {}}
        self._selection_freshness_metrics: dict[str, dict] = {"KR": {}, "US": {}}
        self.candidate_health_trackers: dict[str, Optional[CandidateHealthTracker]] = {"KR": None, "US": None}
        self.today_universe: dict = {}
        self._applied_fill_keys: set[str] = set()
        self._applied_fill_key_order: deque[str] = deque()
        self.tuning_count = 0
        self._last_tune_result: dict[str, dict] = {"KR": {}, "US": {}}
        self._tune_maintain_streak: dict[str, int] = {"KR": 0, "US": 0}
        # 30분 간격 지수 변동률 히스토리 (시장별, 최대 8개 = 4시간)
        self._index_history: dict[str, deque] = {
            "KR": deque(maxlen=8),
            "US": deque(maxlen=8),
        }
        self._active_session_date: dict[str, Optional[date]] = {"KR": None, "US": None}
        self.ws_by_market: dict[str, Optional[KISWebSocket]] = {"KR": None, "US": None}
        self.price_cache = {}
