        self._session_startup_guard_sec: dict[str, float] = {"KR": _STARTUP_GUARD_SEC, "US": _STARTUP_GUARD_SEC}
        self._daily_baseline_by_market: dict[str, dict] = {"KR": {}, "US": {}}
